/* =========================================================================
   QUEST REQUIREMENTS — skill levels, quest points, and prerequisite quests
   for each quest, used to work out which quests a synced player can or
   cannot currently do (see storage.js questEligibility()).

   Auto-generated — do NOT hand-edit the bulk entries; regenerate from the
   source dataset instead. Source: RS-Quest-Viewer quest_list.json.
   Skill ids match RUNEMETRICS_SKILL_IDS (data.js). Keys are normalised
   quest titles (see normaliseQuestKey below) so they line up with the
   titles RuneMetrics returns despite minor casing/punctuation differences.

   Known gap: this dataset predates the newest quests, so a handful of
   recent quests have no entry here — the app treats those as 'unknown
   requirements' rather than guessing. 56 of them have been added below as
   uncompiled "__stub" entries (see the MANUALLY ADDED STUBS block near the
   end of this file) pending hand compilation of their skills/prerequisites.
   ========================================================================= */

/** Normalises a quest title to its lookup key: lowercase, '&'→'and',
 *  apostrophes dropped, any run of non-alphanumerics collapsed to one space.
 *  Must stay in sync with the generator that built QUEST_REQUIREMENTS. */
export function normaliseQuestKey(title){
  return String(title)
    .toLowerCase()
    .replace(/&/g, 'and')
    .replace(/[\u2019']/g, '')
    .replace(/\([^)]*\)/g, ' ')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

